interface.definition:
#"SYSTEM_SYSRULES_headerContentLayout"(
  header: #"SYSTEM_SYSRULES_cardLayout"(
    contents: {
      #"SYSTEM_SYSRULES_headingField"(
        text: if(
          ri!isUpdate,
          "Update Participant",
          "Create Participant"
        ),
        size: "LARGE",
        fontWeight: "SEMI_BOLD"
      ),
      #"SYSTEM_SYSRULES_richTextDisplayField"(
        labelPosition: "COLLAPSED",
        value: {
          if(
            ri!isUpdate,
            "Update details for the participant",
            "Enter details for the participant"
          )
        }
      )
    },
    style: "ACCENT",
    padding: "STANDARD",
    showBorder: false
  ),
  isHeaderFixed: true,
  contents: {
    #"SYSTEM_SYSRULES_columnsLayout"(
      columns: {
        #"SYSTEM_SYSRULES_columnLayout"(
          showWhen: #"SYSTEM_SYSRULES_isPageWidth"(
            {
              "DESKTOP_WIDE",
              "DESKTOP",
              "DESKTOP_NARROW",
              "TABLET_LANDSCAPE"
            }
          )
        ),
        #"SYSTEM_SYSRULES_columnLayout"(
          contents: {
            #"SYSTEM_SYSRULES_sectionLayout_v1"(
              contents: {
                #"SYSTEM_SYSRULES_cardLayout"(
                  contents: {
                    #"SYSTEM_SYSRULES_radioButtonField_v1"(
                      data: #"urn:appian:record-type:v1:c035ef79-0201-4600-a2b7-9075b42e1d87",
                      choiceLabels: #"urn:appian:record-field:v1:c035ef79-0201-4600-a2b7-9075b42e1d87/83d6cf30-3b09-4a38-89c5-2de99cf67942",
                      choiceValues: #"urn:appian:record-field:v1:c035ef79-0201-4600-a2b7-9075b42e1d87/18523cc9-885d-4706-a91b-efc4cc8eda99",
                      label: "Participants To Prison",
                      labelPosition: "ABOVE",
                      value: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/cce64326-22d6-4079-a39f-cb5e0292e234"],
                      saveInto: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/cce64326-22d6-4079-a39f-cb5e0292e234"],
                      required: true,
                      choiceLayout: "COMPACT",
                      choiceStyle: "CARDS"
                    ),
                    #"SYSTEM_SYSRULES_integerField"(
                      label: "Booking Number",
                      labelPosition: "ABOVE",
                      value: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/5bd820c3-9636-46f6-a807-71831615e1ae"],
                      saveInto: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/5bd820c3-9636-46f6-a807-71831615e1ae"],
                      required: true,
                      marginAbove: "LESS"
                    ),
                    #"SYSTEM_SYSRULES_pickerFieldUsers"(
                      label: "User",
                      groupFilter: #"_a-0000ee09-79c9-8000-9bf0-011c48011c48_1487564",
                      value: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/02011db0-86ad-4cf2-bf76-8358c5fd0dc2"],
                      saveInto: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/02011db0-86ad-4cf2-bf76-8358c5fd0dc2"]
                    ),
                    #"SYSTEM_SYSRULES_dateField"(
                      label: "Born On",
                      labelPosition: "ABOVE",
                      value: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/bbb02f76-6d20-4cc7-b768-a46ba483418d"],
                      saveInto: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/bbb02f76-6d20-4cc7-b768-a46ba483418d"],
                      required: true,
                      marginAbove: "LESS"
                    ),
                    #"SYSTEM_SYSRULES_textField"(
                      label: "Type",
                      labelPosition: "ABOVE",
                      value: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/97aeefb7-1a0b-494a-95bc-7b73a9e490d3"],
                      saveInto: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/97aeefb7-1a0b-494a-95bc-7b73a9e490d3"],
                      characterLimit: 255,
                      showCharacterCount: false,
                      required: true,
                      marginAbove: "LESS"
                    ),
                    #"SYSTEM_SYSRULES_textField"(
                      label: "Position",
                      labelPosition: "ABOVE",
                      value: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/6e4c5732-924a-42ac-8c76-c8abc7bd517f"],
                      saveInto: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/6e4c5732-924a-42ac-8c76-c8abc7bd517f"],
                      characterLimit: 255,
                      showCharacterCount: false,
                      required: true,
                      marginAbove: "LESS"
                    ),
                    #"SYSTEM_SYSRULES_textField"(
                      label: "Workplace",
                      labelPosition: "ABOVE",
                      value: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/638a87b1-c963-41c0-8915-e96b9ae9bb76"],
                      saveInto: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/638a87b1-c963-41c0-8915-e96b9ae9bb76"],
                      characterLimit: 255,
                      showCharacterCount: false,
                      required: true,
                      marginAbove: "LESS"
                    )
                  },
                  style: "NONE",
                  shape: "SEMI_ROUNDED",
                  padding: "MORE"
                )
              },
              marginBelow: "MORE"
            ),
            #"SYSTEM_SYSRULES_ButtonLayout"(
              primaryButtons: {
                #"SYSTEM_SYSRULES_buttonWidget_v1"(
                  label: if(
                    ri!isUpdate,
                    "Save",
                    "Create"
                  ),
                  saveInto: {
                    if(
                      ri!isUpdate,
                      {
                        a!save(
                          target: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/5fab8792-7366-4410-9b07-b90607f98c83"],
                          value: loggedInUser()
                        ),
                        a!save(
                          target: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/4f89af58-9d90-496d-80f1-00d8828e3989"],
                          value: now()
                        )
                      },
                      {
                        a!save(
                          target: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/1b8345a2-3afe-4e2d-96b4-b02e1f90b3db"],
                          value: loggedInUser()
                        ),
                        a!save(
                          target: ri!participant[#"urn:appian:record-field:v1:3854eb39-6a61-48cd-82b6-e4645b2900fe/982a2827-75ef-4cb8-ab14-698423272249"],
                          value: now()
                        )
                      }
                    )
                  },
                  submit: true,
                  style: "SOLID",
                  validate: true
                )
              },
              secondaryButtons: {
                #"SYSTEM_SYSRULES_buttonWidget_v1"(
                  label: "Cancel",
                  value: true,
                  saveInto: ri!cancel,
                  submit: true,
                  style: "OUTLINE",
                  validate: false
                )
              }
            )
          },
          width: "WIDE"
        ),
        #"SYSTEM_SYSRULES_columnLayout"(
          showWhen: #"SYSTEM_SYSRULES_isPageWidth"(
            {
              "DESKTOP_WIDE",
              "DESKTOP",
              "DESKTOP_NARROW",
              "TABLET_LANDSCAPE"
            }
          )
        )
      }
    )
  },
  backgroundColor: "#fbfbfb"
)
